import type { PrismaClient } from '../../generated/prisma/client.js';

export async function seedAmbitious(prisma: PrismaClient, catMap: Record<string, string>) {
  await prisma.quiz.upsert({
    where: { slug: 'ambitious' },
    update: {
      title: { es: '¿Qué tipo de ambicioso/a eres?', en: 'What kind of ambitious person are you?', fr: 'Quel type d\'ambitieux/se êtes-vous?', de: 'Welcher Typ Ehrgeiziger bist du?', it: 'Che tipo di ambizioso/a sei?', pt: 'Que tipo de ambicioso/a você é?' },
      description: { es: 'La ambición mueve el mundo, pero no toda ambición es igual. ¿Qué mueve la tuya?', en: 'Ambition moves the world, but not all ambition is the same. What drives yours?', fr: 'L\'ambition fait bouger le monde, mais toutes les ambitions ne se valent pas. Qu\'est-ce qui anime la vôtre?', de: 'Ehrgeiz bewegt die Welt, aber nicht jeder Ehrgeiz ist gleich. Was treibt deinen an?', it: 'L\'ambizione muove il mondo, ma non tutta l\'ambizione è uguale. Cosa guida la tua?', pt: 'A ambição move o mundo, mas nem toda ambição é igual. O que move a sua?' },
      scenarioLabel: { es: 'Escenario', en: 'Scenario', fr: 'Scénario', de: 'Szenario', it: 'Scenario', pt: 'Cenário' },
      dimensionLabels: {
        es: { E: 'Éxito Externo', I: 'Impacto', A: 'Autonomía', C: 'Crecimiento' },
        en: { E: 'External Success', I: 'Impact', A: 'Autonomy', C: 'Growth' },
        fr: { E: 'Succès Externe', I: 'Impact', A: 'Autonomie', C: 'Croissance' },
        de: { E: 'Äußerer Erfolg', I: 'Wirkung', A: 'Autonomie', C: 'Wachstum' },
        it: { E: 'Successo Esterno', I: 'Impatto', A: 'Autonomia', C: 'Crescita' },
        pt: { E: 'Sucesso Externo', I: 'Impacto', A: 'Autonomia', C: 'Crescimento' },
      },
      questions: [
        { id: 1, situation: { es: 'Te ofrecen un trabajo muy bien pagado que no te apasiona pero te dará seguridad y estatus. ¿Qué priorizas?', en: 'You are offered a very well-paid job that doesn\'t excite you but will give you security and status. What do you prioritize?', fr: 'On vous propose un travail très bien rémunéré qui ne vous passionne pas mais qui vous apportera sécurité et statut. Que priorisez-vous?', de: 'Dir wird eine sehr gut bezahlte Stelle angeboten, die dich nicht begeistert, aber dir Sicherheit und Status verschafft. Was priorisierst du?', it: 'Ti viene offerto un lavoro molto ben pagato che non ti appassiona ma ti darà sicurezza e status. Cosa priorizzi?', pt: 'Você recebe uma oferta de emprego muito bem pago que não te apaixona, mas que vai te dar segurança e status. O que você prioriza?' }, options: [{ text: { es: 'El dinero y el estatus. La pasión se cultiva, la estabilidad se construye.', en: 'Money and status. Passion can be cultivated, stability is built.', fr: 'L\'argent et le statut. La passion se cultive, la stabilité se construit.', de: 'Geld und Status. Leidenschaft kann kultiviert werden, Stabilität wird aufgebaut.', it: 'I soldi e lo status. La passione si coltiva, la stabilità si costruisce.', pt: 'O dinheiro e o status. A paixão se cultiva, a estabilidade se constrói.' }, dimension: 'E' }, { text: { es: 'Solo si genera algo real: cambia algo, ayuda a alguien.', en: 'Only if it creates something real: changes something, helps someone.', fr: 'Seulement si cela génère quelque chose de réel: change quelque chose, aide quelqu\'un.', de: 'Nur wenn es etwas Reales erzeugt: etwas verändert, jemandem hilft.', it: 'Solo se genera qualcosa di reale: cambia qualcosa, aiuta qualcuno.', pt: 'Somente se gerar algo real: mudar algo, ajudar alguém.' }, dimension: 'I' }, { text: { es: 'La flexibilidad y el control sobre mi tiempo. El dinero importa menos que la autonomía.', en: 'Flexibility and control over my time. Money matters less than autonomy.', fr: 'La flexibilité et le contrôle sur mon temps. L\'argent importe moins que l\'autonomie.', de: 'Flexibilität und Kontrolle über meine Zeit. Geld ist weniger wichtig als Autonomie.', it: 'La flessibilità e il controllo sul mio tempo. I soldi contano meno dell\'autonomia.', pt: 'A flexibilidade e o controle sobre meu tempo. O dinheiro importa menos que a autonomia.' }, dimension: 'A' }, { text: { es: 'Aprendo algo nuevo? ¿Me hace mejor? Eso es lo que evalúo.', en: 'Will I learn something new? Will it make me better? That\'s what I evaluate.', fr: 'Vais-je apprendre quelque chose de nouveau? Cela me rendra-t-il meilleur? C\'est ce que j\'évalue.', de: 'Lerne ich etwas Neues? Macht es mich besser? Das ist, was ich bewerte.', it: 'Imparerò qualcosa di nuovo? Mi renderà migliore? Questo è quello che valuto.', pt: 'Vou aprender algo novo? Vai me tornar melhor? Isso é o que avalio.' }, dimension: 'C' }] },
        { id: 2, situation: { es: '¿Qué significaría para ti haber "triunfado" en la vida?', en: 'What would it mean to you to have "succeeded" in life?', fr: 'Qu\'est-ce que cela signifierait pour vous d\'avoir "réussi" dans la vie?', de: 'Was würde es für dich bedeuten, im Leben "erfolgreich" gewesen zu sein?', it: 'Cosa significherebbe per te aver "trionfato" nella vita?', pt: 'O que significaria para você ter "triunfado" na vida?' }, options: [{ text: { es: 'Tener un nombre reconocido, recursos abundantes y respeto en mi campo.', en: 'Having a recognized name, abundant resources, and respect in my field.', fr: 'Avoir un nom reconnu, des ressources abondantes et du respect dans mon domaine.', de: 'Einen anerkannten Namen, reichliche Ressourcen und Respekt in meinem Bereich zu haben.', it: 'Avere un nome riconosciuto, risorse abbondanti e rispetto nel mio campo.', pt: 'Ter um nome reconhecido, recursos abundantes e respeito na minha área.' }, dimension: 'E' }, { text: { es: 'Haber cambiado la vida de personas de forma real y medible.', en: 'Having changed people\'s lives in a real and measurable way.', fr: 'Avoir changé la vie des gens de manière réelle et mesurable.', de: 'Das Leben von Menschen auf eine reale und messbare Weise verändert zu haben.', it: 'Aver cambiato la vita delle persone in modo reale e misurabile.', pt: 'Ter mudado a vida de pessoas de forma real e mensurável.' }, dimension: 'I' }, { text: { es: 'Vivir exactamente como quiero, sin que nadie me diga qué hacer.', en: 'Living exactly as I want, without anyone telling me what to do.', fr: 'Vivre exactement comme je veux, sans que personne ne me dise quoi faire.', de: 'Genau so zu leben, wie ich will, ohne dass mir jemand sagt, was ich tun soll.', it: 'Vivere esattamente come voglio, senza che nessuno mi dica cosa fare.', pt: 'Viver exatamente como quero, sem que ninguém me diga o que fazer.' }, dimension: 'A' }, { text: { es: 'Haber llegado a mi mejor versión, aunque nadie lo sepa.', en: 'Having reached my best self, even if nobody knows it.', fr: 'Avoir atteint ma meilleure version, même si personne ne le sait.', de: 'Meine beste Version erreicht zu haben, auch wenn es niemand weiß.', it: 'Essere arrivato/a alla mia migliore versione, anche se nessuno lo sa.', pt: 'Ter chegado à minha melhor versão, mesmo que ninguém saiba.' }, dimension: 'C' }] },
        { id: 3, situation: { es: 'Puedes elegir entre dos proyectos: uno te hará famoso/a, el otro cambiará silenciosamente la vida de miles.', en: 'You can choose between two projects: one will make you famous, the other will quietly change the lives of thousands.', fr: 'Vous pouvez choisir entre deux projets: l\'un vous rendra célèbre, l\'autre changera silencieusement la vie de milliers de personnes.', de: 'Du kannst zwischen zwei Projekten wählen: Eines wird dich berühmt machen, das andere wird still das Leben von Tausenden verändern.', it: 'Puoi scegliere tra due progetti: uno ti renderà famoso/a, l\'altro cambierà silenziosamente la vita di migliaia.', pt: 'Você pode escolher entre dois projetos: um vai te tornar famoso/a, o outro vai mudar silenciosamente a vida de milhares.' }, options: [{ text: { es: 'El que me da visibilidad. El impacto que no se ve no me mueve igual.', en: 'The one that gives me visibility. Impact that can\'t be seen doesn\'t move me the same way.', fr: 'Celui qui me donne de la visibilité. L\'impact qu\'on ne voit pas ne m\'anime pas autant.', de: 'Das, das mir Sichtbarkeit gibt. Wirkung, die man nicht sieht, bewegt mich nicht genauso.', it: 'Quello che mi dà visibilità. L\'impatto che non si vede non mi motiva allo stesso modo.', pt: 'O que me dá visibilidade. O impacto que não se vê não me move da mesma forma.' }, dimension: 'E' }, { text: { es: 'El que cambia vidas. La fama sin impacto real es ruido.', en: 'The one that changes lives. Fame without real impact is just noise.', fr: 'Celui qui change des vies. La célébrité sans impact réel n\'est que du bruit.', de: 'Das, das Leben verändert. Ruhm ohne reale Wirkung ist Lärm.', it: 'Quello che cambia vite. La fama senza impatto reale è solo rumore.', pt: 'O que muda vidas. A fama sem impacto real é apenas ruído.' }, dimension: 'I' }, { text: { es: 'El que me da más control sobre cómo trabajo y vivo.', en: 'The one that gives me more control over how I work and live.', fr: 'Celui qui me donne plus de contrôle sur la façon dont je travaille et vis.', de: 'Das, das mir mehr Kontrolle darüber gibt, wie ich arbeite und lebe.', it: 'Quello che mi dà più controllo su come lavoro e vivo.', pt: 'O que me dá mais controle sobre como trabalho e vivo.' }, dimension: 'A' }, { text: { es: 'El que me enseña más y me hace crecer más como profesional.', en: 'The one that teaches me more and helps me grow the most as a professional.', fr: 'Celui qui m\'apprend le plus et me fait le plus grandir en tant que professionnel.', de: 'Das, das mich mehr lehrt und mich als Profi am meisten wachsen lässt.', it: 'Quello che mi insegna di più e mi fa crescere di più come professionista.', pt: 'O que me ensina mais e me faz crescer mais como profissional.' }, dimension: 'C' }] },
        { id: 4, situation: { es: '¿Cuál es tu relación con el fracaso?', en: 'What is your relationship with failure?', fr: 'Quelle est votre relation avec l\'échec?', de: 'Was ist deine Beziehung zum Scheitern?', it: 'Qual è il tuo rapporto con il fallimento?', pt: 'Qual é a sua relação com o fracasso?' }, options: [{ text: { es: 'Es difícil. Fracasar en público me cuesta especialmente.', en: 'It\'s hard. Failing publicly is especially difficult for me.', fr: 'C\'est difficile. Échouer en public m\'est particulièrement difficile.', de: 'Es ist schwer. In der Öffentlichkeit zu scheitern fällt mir besonders schwer.', it: 'È difficile. Fallire in pubblico mi costa particolarmente.', pt: 'É difícil. Fracassar em público é especialmente custoso para mim.' }, dimension: 'E' }, { text: { es: 'Lo acepto si viene de intentar hacer algo que importa.', en: 'I accept it if it comes from trying to do something that matters.', fr: 'Je l\'accepte si cela vient d\'une tentative de faire quelque chose qui compte.', de: 'Ich akzeptiere es, wenn es davon kommt, etwas zu versuchen, das wichtig ist.', it: 'Lo accetto se viene dal tentativo di fare qualcosa che conta.', pt: 'Aceito se vem de tentar fazer algo que importa.' }, dimension: 'I' }, { text: { es: 'Lo vivo mejor si lo elegí yo, no si me fue impuesto.', en: 'I handle it better if I chose it, not if it was imposed on me.', fr: 'Je le vis mieux si je l\'ai choisi, pas s\'il m\'a été imposé.', de: 'Ich gehe damit besser um, wenn ich es gewählt habe, nicht wenn es mir aufgezwungen wurde.', it: 'Lo vivo meglio se l\'ho scelto io, non se mi è stato imposto.', pt: 'Lido melhor com ele se foi uma escolha minha, não se foi imposto.' }, dimension: 'A' }, { text: { es: 'Es información valiosa. Me dice qué necesito aprender.', en: 'It\'s valuable information. It tells me what I need to learn.', fr: 'C\'est une information précieuse. Cela me dit ce que je dois apprendre.', de: 'Es ist wertvolle Information. Es sagt mir, was ich lernen muss.', it: 'È un\'informazione preziosa. Mi dice cosa ho bisogno di imparare.', pt: 'É informação valiosa. Me diz o que preciso aprender.' }, dimension: 'C' }] },
        { id: 5, situation: { es: 'Un mentor influyente te ofrece guiarte, pero a cambio tendrás que seguir su visión, no la tuya.', en: 'An influential mentor offers to guide you, but in exchange you will have to follow their vision, not yours.', fr: 'Un mentor influent vous propose de vous guider, mais en échange vous devrez suivre sa vision, pas la vôtre.', de: 'Ein einflussreicher Mentor bietet an, dich zu führen, aber dafür musst du seine Vision verfolgen, nicht deine.', it: 'Un mentore influente ti offre di guidarti, ma in cambio dovrai seguire la sua visione, non la tua.', pt: 'Um mentor influente oferece orientá-lo, mas em troca você terá que seguir a visão dele, não a sua.' }, options: [{ text: { es: 'Lo acepto. El acceso a su red y su nombre vale el compromiso.', en: 'I accept it. Access to their network and name is worth the compromise.', fr: 'Je l\'accepte. L\'accès à son réseau et à son nom vaut le compromis.', de: 'Ich akzeptiere es. Der Zugang zu seinem Netzwerk und seinem Namen ist den Kompromiss wert.', it: 'Lo accetto. L\'accesso alla sua rete e al suo nome vale il compromesso.', pt: 'Aceito. O acesso à sua rede e seu nome vale o compromisso.' }, dimension: 'E' }, { text: { es: 'Depende de si su visión genera el mismo impacto que la mía.', en: 'It depends on whether their vision generates the same impact as mine.', fr: 'Cela dépend de si sa vision génère le même impact que la mienne.', de: 'Es hängt davon ab, ob seine Vision denselben Impact erzeugt wie meine.', it: 'Dipende se la sua visione genera lo stesso impatto della mia.', pt: 'Depende se a visão dele gera o mesmo impacto que a minha.' }, dimension: 'I' }, { text: { es: 'Lo rechazo. Prefiero construir más despacio con mi propia visión.', en: 'I turn it down. I prefer to build more slowly with my own vision.', fr: 'Je refuse. Je préfère construire plus lentement avec ma propre vision.', de: 'Ich lehne es ab. Ich baue lieber langsamer mit meiner eigenen Vision.', it: 'Lo rifiuto. Preferisco costruire più lentamente con la mia visione.', pt: 'Recuso. Prefiro construir mais devagar com minha própria visão.' }, dimension: 'A' }, { text: { es: 'Depende de cuánto puedo aprender de él/ella en el proceso.', en: 'It depends on how much I can learn from them in the process.', fr: 'Cela dépend de combien je peux apprendre d\'eux dans le processus.', de: 'Es hängt davon ab, wie viel ich von ihm/ihr im Prozess lernen kann.', it: 'Dipende da quanto posso imparare da lui/lei nel processo.', pt: 'Depende de quanto posso aprender com ele/ela no processo.' }, dimension: 'C' }] },
        { id: 6, situation: { es: '¿Qué te motiva más a trabajar duro?', en: 'What motivates you most to work hard?', fr: 'Qu\'est-ce qui vous motive le plus à travailler dur?', de: 'Was motiviert dich am meisten, hart zu arbeiten?', it: 'Cosa ti motiva di più a lavorare sodo?', pt: 'O que te motiva mais a trabalhar duro?' }, options: [{ text: { es: 'El reconocimiento de pares y la posición que construyo.', en: 'Peer recognition and the position I\'m building.', fr: 'La reconnaissance de mes pairs et la position que je construis.', de: 'Die Anerkennung von Gleichgestellten und die Position, die ich aufbaue.', it: 'Il riconoscimento dei colleghi e la posizione che sto costruendo.', pt: 'O reconhecimento dos pares e a posição que estou construindo.' }, dimension: 'E' }, { text: { es: 'Saber que lo que hago importa y tiene un efecto real.', en: 'Knowing that what I do matters and has a real effect.', fr: 'Savoir que ce que je fais compte et a un effet réel.', de: 'Zu wissen, dass das, was ich tue, wichtig ist und eine reale Wirkung hat.', it: 'Sapere che quello che faccio conta e ha un effetto reale.', pt: 'Saber que o que faço importa e tem um efeito real.' }, dimension: 'I' }, { text: { es: 'La libertad que me da no depender de nadie.', en: 'The freedom that comes from not depending on anyone.', fr: 'La liberté que cela me donne de ne dépendre de personne.', de: 'Die Freiheit, die es mir gibt, von niemandem abhängig zu sein.', it: 'La libertà che mi dà non dipendere da nessuno.', pt: 'A liberdade que me dá não depender de ninguém.' }, dimension: 'A' }, { text: { es: 'La sensación de mejorar, de ser hoy mejor que ayer.', en: 'The feeling of improving, of being better today than yesterday.', fr: 'La sensation de progresser, d\'être meilleur aujourd\'hui qu\'hier.', de: 'Das Gefühl, sich zu verbessern, heute besser zu sein als gestern.', it: 'La sensazione di migliorare, di essere oggi migliore di ieri.', pt: 'A sensação de melhorar, de ser hoje melhor do que ontem.' }, dimension: 'C' }] },
        { id: 7, situation: { es: 'Tienes que elegir entre un ascenso con más poder o un rol horizontal con más aprendizaje.', en: 'You have to choose between a promotion with more power or a lateral role with more learning.', fr: 'Vous devez choisir entre une promotion avec plus de pouvoir ou un rôle horizontal avec plus d\'apprentissage.', de: 'Du musst zwischen einer Beförderung mit mehr Macht oder einer lateralen Rolle mit mehr Lernen wählen.', it: 'Devi scegliere tra una promozione con più potere o un ruolo orizzontale con più apprendimento.', pt: 'Você tem que escolher entre uma promoção com mais poder ou um cargo lateral com mais aprendizado.' }, options: [{ text: { es: 'El ascenso. El poder amplifica todo lo demás.', en: 'The promotion. Power amplifies everything else.', fr: 'La promotion. Le pouvoir amplifie tout le reste.', de: 'Die Beförderung. Macht verstärkt alles andere.', it: 'La promozione. Il potere amplifica tutto il resto.', pt: 'A promoção. O poder amplifica tudo o mais.' }, dimension: 'E' }, { text: { es: 'El que me permita tener más impacto, sea cual sea.', en: 'Whichever allows me to have more impact, regardless.', fr: 'Celui qui me permet d\'avoir plus d\'impact, quel qu\'il soit.', de: 'Das, das mir mehr Impact ermöglicht, egal welches.', it: 'Quello che mi permette di avere più impatto, qualunque esso sia.', pt: 'O que me permita ter mais impacto, seja qual for.' }, dimension: 'I' }, { text: { es: 'El horizontal. Más aprendizaje, más opciones futuras, más libertad.', en: 'The lateral one. More learning, more future options, more freedom.', fr: 'Le rôle horizontal. Plus d\'apprentissage, plus d\'options futures, plus de liberté.', de: 'Der laterale. Mehr Lernen, mehr zukünftige Optionen, mehr Freiheit.', it: 'Quello orizzontale. Più apprendimento, più opzioni future, più libertà.', pt: 'O lateral. Mais aprendizado, mais opções futuras, mais liberdade.' }, dimension: 'A' }, { text: { es: 'El de más aprendizaje. Siempre.', en: 'The one with more learning. Always.', fr: 'Celui avec plus d\'apprentissage. Toujours.', de: 'Das mit mehr Lernen. Immer.', it: 'Quello con più apprendimento. Sempre.', pt: 'O de mais aprendizado. Sempre.' }, dimension: 'C' }] },
        { id: 8, situation: { es: '¿Qué es lo que más te frustra de las personas que trabajan sin ambición?', en: 'What frustrates you most about people who work without ambition?', fr: 'Qu\'est-ce qui vous frustre le plus chez les gens qui travaillent sans ambition?', de: 'Was frustriert dich am meisten an Menschen, die ohne Ehrgeiz arbeiten?', it: 'Cosa ti frustra di più nelle persone che lavorano senza ambizione?', pt: 'O que mais te frustra nas pessoas que trabalham sem ambição?' }, options: [{ text: { es: 'Que desperdician su potencial de crear algo grande.', en: 'That they waste their potential to create something great.', fr: 'Qu\'ils gaspillent leur potentiel pour créer quelque chose de grand.', de: 'Dass sie ihr Potenzial verschwenden, etwas Großes zu schaffen.', it: 'Che sprecano il loro potenziale per creare qualcosa di grande.', pt: 'Que desperdiçam seu potencial de criar algo grande.' }, dimension: 'E' }, { text: { es: 'Que su falta de ambición los lleva a no mejorar el mundo cuando podrían.', en: 'That their lack of ambition leads them to not improve the world when they could.', fr: 'Que leur manque d\'ambition les amène à ne pas améliorer le monde alors qu\'ils le pourraient.', de: 'Dass ihr mangelnder Ehrgeiz dazu führt, dass sie die Welt nicht verbessern, obwohl sie es könnten.', it: 'Che la loro mancanza di ambizione li porta a non migliorare il mondo quando potrebbero.', pt: 'Que a falta de ambição os leva a não melhorar o mundo quando poderiam.' }, dimension: 'I' }, { text: { es: 'Que se dejan llevar por sistemas que no los representan sin cuestionarlos.', en: 'That they let themselves be swept along by systems that don\'t represent them without questioning them.', fr: 'Qu\'ils se laissent emporter par des systèmes qui ne les représentent pas sans les remettre en question.', de: 'Dass sie sich von Systemen mitreißen lassen, die sie nicht repräsentieren, ohne sie zu hinterfragen.', it: 'Che si lasciano trascinare da sistemi che non li rappresentano senza metterli in discussione.', pt: 'Que se deixam levar por sistemas que não os representam sem questioná-los.' }, dimension: 'A' }, { text: { es: 'Que se estancan y dejan de aprender.', en: 'That they stagnate and stop learning.', fr: 'Qu\'ils stagnent et arrêtent d\'apprendre.', de: 'Dass sie stagnieren und aufhören zu lernen.', it: 'Che si bloccano e smettono di imparare.', pt: 'Que estagnam e param de aprender.' }, dimension: 'C' }] },
        { id: 9, situation: { es: 'Tienes la oportunidad de dar un salto enorme en tu carrera, pero requiere sacrificar relaciones importantes.', en: 'You have the opportunity to make a huge leap in your career, but it requires sacrificing important relationships.', fr: 'Vous avez l\'opportunité de faire un grand bond dans votre carrière, mais cela nécessite de sacrifier des relations importantes.', de: 'Du hast die Möglichkeit, einen enormen Sprung in deiner Karriere zu machen, aber es erfordert, wichtige Beziehungen zu opfern.', it: 'Hai l\'opportunità di fare un grande salto nella tua carriera, ma richiede di sacrificare relazioni importanti.', pt: 'Você tem a oportunidade de dar um salto enorme na carreira, mas requer sacrificar relacionamentos importantes.' }, options: [{ text: { es: 'Lo evalúo seriamente. Hay etapas de la vida donde hay que priorizar.', en: 'I evaluate it seriously. There are stages in life where you have to prioritize.', fr: 'Je l\'évalue sérieusement. Il y a des étapes de la vie où il faut prioriser.', de: 'Ich bewerte es ernsthaft. Es gibt Phasen im Leben, in denen man priorisieren muss.', it: 'Lo valuto seriamente. Ci sono fasi della vita in cui bisogna dare priorità.', pt: 'Avalio seriamente. Há etapas da vida em que se precisa priorizar.' }, dimension: 'E' }, { text: { es: 'Solo si ese salto tiene un propósito que lo justifique más allá del éxito personal.', en: 'Only if that leap has a purpose that justifies it beyond personal success.', fr: 'Seulement si ce bond a un objectif qui le justifie au-delà du succès personnel.', de: 'Nur wenn dieser Sprung einen Zweck hat, der ihn jenseits persönlichen Erfolgs rechtfertigt.', it: 'Solo se quel salto ha uno scopo che lo giustifica al di là del successo personale.', pt: 'Somente se esse salto tiver um propósito que o justifique além do sucesso pessoal.' }, dimension: 'I' }, { text: { es: 'Busco la forma de hacer el salto sin sacrificar lo que más valoro.', en: 'I look for a way to make the leap without sacrificing what I value most.', fr: 'Je cherche une façon de faire le bond sans sacrifier ce que je valorise le plus.', de: 'Ich suche nach einer Möglichkeit, den Sprung zu machen, ohne das zu opfern, was mir am wichtigsten ist.', it: 'Cerco il modo di fare il salto senza sacrificare ciò che valuto di più.', pt: 'Procuro a forma de dar o salto sem sacrificar o que mais valorizo.' }, dimension: 'A' }, { text: { es: 'Si el crecimiento profesional destruye lo que construí, algo en la ecuación está mal.', en: 'If professional growth destroys what I\'ve built, something in the equation is wrong.', fr: 'Si la croissance professionnelle détruit ce que j\'ai construit, quelque chose dans l\'équation est faux.', de: 'Wenn berufliches Wachstum das zerstört, was ich aufgebaut habe, stimmt etwas in der Gleichung nicht.', it: 'Se la crescita professionale distrugge quello che ho costruito, qualcosa nell\'equazione è sbagliato.', pt: 'Se o crescimento profissional destrói o que construí, algo na equação está errado.' }, dimension: 'C' }] },
        { id: 10, situation: { es: 'Al final de tu carrera, ¿qué quieres que digan de ti?', en: 'At the end of your career, what do you want people to say about you?', fr: 'À la fin de votre carrière, que voulez-vous qu\'on dise de vous?', de: 'Am Ende deiner Karriere, was willst du, dass die Leute über dich sagen?', it: 'Alla fine della tua carriera, cosa vuoi che dicano di te?', pt: 'No final da sua carreira, o que você quer que digam sobre você?' }, options: [{ text: { es: '"Llegó muy lejos. Era brillante y todos lo sabían."', en: '"They went very far. They were brilliant, and everyone knew it."', fr: '"Il/elle est allé(e) très loin. Il/elle était brillant(e) et tout le monde le savait."', de: '"Er/Sie ist sehr weit gekommen. Er/Sie war brilliant und alle wussten es."', it: '"È arrivato/a molto lontano. Era brillante e tutti lo sapevano."', pt: '"Foi muito longe. Era brilhante e todos sabiam."' }, dimension: 'E' }, { text: { es: '"Cambió algo. Antes de él/ella, esto era diferente."', en: '"They changed something. Before them, this was different."', fr: '"Il/elle a changé quelque chose. Avant lui/elle, c\'était différent."', de: '"Er/Sie hat etwas verändert. Vor ihm/ihr war das anders."', it: '"Ha cambiato qualcosa. Prima di lui/lei, era diverso."', pt: '"Mudou algo. Antes dele/dela, isso era diferente."' }, dimension: 'I' }, { text: { es: '"Vivió en sus propios términos. Nunca transigió su independencia."', en: '"They lived on their own terms. They never compromised their independence."', fr: '"Il/elle a vécu selon ses propres termes. Il/elle n\'a jamais transigé sur son indépendance."', de: '"Er/Sie lebte nach seinen/ihren eigenen Bedingungen. Er/Sie hat seine/ihre Unabhängigkeit nie kompromittiert."', it: '"Ha vissuto alle sue condizioni. Non ha mai compromesso la sua indipendenza."', pt: '"Viveu nos seus próprios termos. Nunca comprometeu a sua independência."' }, dimension: 'A' }, { text: { es: '"Nunca dejó de aprender y crecer. Era mejor cada año."', en: '"They never stopped learning and growing. They were better every year."', fr: '"Il/elle n\'a jamais arrêté d\'apprendre et de grandir. Il/elle était meilleur(e) chaque année."', de: '"Er/Sie hörte nie auf zu lernen und zu wachsen. Er/Sie wurde jedes Jahr besser."', it: '"Non ha mai smesso di imparare e crescere. Era migliore ogni anno."', pt: '"Nunca parou de aprender e crescer. Era melhor a cada ano."' }, dimension: 'C' }] },
      ],
      characters: [
        { name: { es: 'El Ambicioso de Éxito', en: 'The Success-Driven Ambitious', fr: 'L\'Ambitieux de la Réussite', de: 'Der Erfolgsambitionierte', it: 'L\'Ambizioso del Successo', pt: 'O Ambicioso de Sucesso' }, dimensions: ['E'], photo: '/characters/success-ambitious.jpg', description: { es: 'Quiere llegar alto y que todos lo vean.', en: 'Wants to reach the top and have everyone see it.', fr: 'Veut aller très haut et que tout le monde le voit.', de: 'Möchte hoch hinaus und dass alle es sehen.', it: 'Vuole arrivare in alto e che tutti lo vedano.', pt: 'Quer chegar alto e que todos vejam.' }, philosophy: { es: 'Para ti, el éxito tiene nombre, número y audiencia. No es vanidad — es la evidencia concreta de que valió la pena el esfuerzo. El reconocimiento externo es el espejo donde mides tu propio valor.', en: 'For you, success has a name, a number, and an audience. It\'s not vanity — it\'s concrete evidence that the effort was worth it. External recognition is the mirror in which you measure your own worth.', fr: 'Pour vous, le succès a un nom, un chiffre et un public. Ce n\'est pas de la vanité — c\'est la preuve concrète que l\'effort en valait la peine. La reconnaissance externe est le miroir dans lequel vous mesurez votre propre valeur.', de: 'Für dich hat Erfolg einen Namen, eine Zahl und ein Publikum. Es ist keine Eitelkeit — es ist der konkrete Beweis, dass die Mühe es wert war. Externe Anerkennung ist der Spiegel, in dem du deinen eigenen Wert misst.', it: 'Per te, il successo ha un nome, un numero e un pubblico. Non è vanità — è la prova concreta che lo sforzo ne è valso la pena. Il riconoscimento esterno è lo specchio in cui misuri il tuo stesso valore.', pt: 'Para você, o sucesso tem nome, número e audiência. Não é vaidade — é a evidência concreta de que o esforço valeu a pena. O reconhecimento externo é o espelho onde você mede o seu próprio valor.' } },
        { name: { es: 'El Ambicioso de Impacto', en: 'The Impact-Driven Ambitious', fr: 'L\'Ambitieux de l\'Impact', de: 'Der Wirkungsorientierte', it: 'L\'Ambizioso dell\'Impatto', pt: 'O Ambicioso de Impacto' }, dimensions: ['I'], photo: '/characters/impact-ambitious.jpg', description: { es: 'Le importa dejar huella, no tener fama.', en: 'Cares about leaving a mark, not gaining fame.', fr: 'S\'intéresse à laisser une empreinte, pas à avoir de la célébrité.', de: 'Wichtig ist, eine Spur zu hinterlassen, nicht berühmt zu werden.', it: 'Gli/Le importa lasciare un\'impronta, non avere fama.', pt: 'Importa-se em deixar uma marca, não em ter fama.' }, philosophy: { es: 'Para ti, la ambición sin propósito es ruido. Quieres que lo que hagas importe, que cambie algo, que quede cuando ya no estés. El éxito sin impacto real es decoración.', en: 'For you, ambition without purpose is noise. You want what you do to matter, to change something, to remain when you\'re gone. Success without real impact is mere decoration.', fr: 'Pour vous, l\'ambition sans but n\'est que du bruit. Vous voulez que ce que vous faites compte, que cela change quelque chose, que cela reste quand vous ne serez plus là. Le succès sans impact réel n\'est que décoration.', de: 'Für dich ist Ehrgeiz ohne Zweck Lärm. Du willst, dass das, was du tust, wichtig ist, etwas verändert, bleibt, wenn du nicht mehr da bist. Erfolg ohne reale Wirkung ist nur Dekoration.', it: 'Per te, l\'ambizione senza scopo è rumore. Vuoi che quello che fai conti, che cambi qualcosa, che rimanga quando non ci sarai più. Il successo senza impatto reale è semplice decorazione.', pt: 'Para você, a ambição sem propósito é ruído. Você quer que o que faz importe, que mude algo, que permaneça quando você não estiver mais aqui. O sucesso sem impacto real é apenas decoração.' } },
        { name: { es: 'El Ambicioso Independiente', en: 'The Independent Ambitious', fr: 'L\'Ambitieux Indépendant', de: 'Der Unabhängige Ehrgeizige', it: 'L\'Ambizioso Indipendente', pt: 'O Ambicioso Independente' }, dimensions: ['A'], photo: '/characters/independent-ambitious.jpg', description: { es: 'Quiere construir, pero en sus propios términos.', en: 'Wants to build, but on their own terms.', fr: 'Veut construire, mais selon ses propres termes.', de: 'Möchte aufbauen, aber zu seinen eigenen Bedingungen.', it: 'Vuole costruire, ma a modo suo.', pt: 'Quer construir, mas nos seus próprios termos.' }, philosophy: { es: 'Tu ambición más profunda es la libertad. No cualquier tipo de éxito — solo el que te permite vivir según tus reglas. Preferirías un negocio pequeño propio que una posición poderosa en el sistema de otro.', en: 'Your deepest ambition is freedom. Not just any kind of success — only the kind that lets you live by your own rules. You would rather have a small business of your own than a powerful position in someone else\'s system.', fr: 'Votre ambition la plus profonde est la liberté. Pas n\'importe quel type de succès — seulement celui qui vous permet de vivre selon vos propres règles. Vous préféreriez une petite entreprise qui vous appartient qu\'une position puissante dans le système de quelqu\'un d\'autre.', de: 'Dein tiefster Ehrgeiz ist die Freiheit. Nicht irgendeine Art von Erfolg — nur der, der es dir ermöglicht, nach deinen eigenen Regeln zu leben. Du würdest lieber ein kleines eigenes Unternehmen haben als eine mächtige Position im System eines anderen.', it: 'La tua ambizione più profonda è la libertà. Non qualsiasi tipo di successo — solo quello che ti permette di vivere secondo le tue regole. Preferiresti una piccola impresa tua che una posizione potente nel sistema di qualcun altro.', pt: 'Sua ambição mais profunda é a liberdade. Não qualquer tipo de sucesso — apenas o que te permite viver segundo as suas regras. Preferiria um pequeno negócio próprio a uma posição poderosa no sistema de outra pessoa.' } },
        { name: { es: 'El Ambicioso de Crecimiento', en: 'The Growth-Driven Ambitious', fr: 'L\'Ambitieux de la Croissance', de: 'Der Wachstumsorientierte', it: 'L\'Ambizioso della Crescita', pt: 'O Ambicioso do Crescimento' }, dimensions: ['C'], photo: '/characters/growth-ambitious.jpg', description: { es: 'Cada día mejor que ayer. Eso es suficiente.', en: 'Better every day than the one before. That is enough.', fr: 'Chaque jour meilleur que la veille. C\'est suffisant.', de: 'Jeden Tag besser als gestern. Das genügt.', it: 'Ogni giorno migliore di ieri. Questo è sufficiente.', pt: 'Cada dia melhor do que o anterior. Isso é suficiente.' }, philosophy: { es: 'Para ti, la ambición es interna. El estándar con quien compites eres tú mismo/a de ayer. No te interesa ser el mejor del mundo — te interesa ser la mejor versión de ti mismo/a.', en: 'For you, ambition is internal. The standard you compete against is your yesterday self. You\'re not interested in being the best in the world — you\'re interested in being the best version of yourself.', fr: 'Pour vous, l\'ambition est interne. La norme avec laquelle vous vous comparez, c\'est vous-même d\'hier. Vous ne cherchez pas à être le meilleur du monde — vous cherchez à être la meilleure version de vous-même.', de: 'Für dich ist Ehrgeiz intern. Der Standard, mit dem du konkurrierst, bist du selbst von gestern. Du interessierst dich nicht dafür, der Beste der Welt zu sein — du interessierst dich dafür, die beste Version deiner selbst zu sein.', it: 'Per te, l\'ambizione è interna. Lo standard con cui gareggi sei tu stesso/a di ieri. Non ti interessa essere il migliore del mondo — ti interessa essere la migliore versione di te stesso/a.', pt: 'Para você, a ambição é interna. O padrão com quem você compete é você mesmo/a de ontem. Não lhe interessa ser o melhor do mundo — lhe interessa ser a melhor versão de si mesmo/a.' } },
        { name: { es: 'El Emprendedor Ambicioso', en: 'The Ambitious Entrepreneur', fr: 'L\'Entrepreneur Ambitieux', de: 'Der Ehrgeizige Unternehmer', it: 'L\'Imprenditore Ambizioso', pt: 'O Empreendedor Ambicioso' }, dimensions: ['E', 'A'], photo: '/characters/entrepreneur.jpg', description: { es: 'Quiere éxito y autonomía. El camino del fundador.', en: 'Wants success and autonomy. The founder\'s path.', fr: 'Veut réussite et autonomie. La voie du fondateur.', de: 'Möchte Erfolg und Autonomie. Der Weg des Gründers.', it: 'Vuole successo e autonomia. Il percorso del fondatore.', pt: 'Quer sucesso e autonomia. O caminho do fundador.' }, philosophy: { es: 'Quieres llegar alto y hacerlo por tu propio camino. La combinación te lleva naturalmente al emprendimiento. No cualquier éxito sirve — solo el que construiste tú.', en: 'You want to reach the top and do it your own way. This combination naturally leads you to entrepreneurship. Not just any success will do — only the one you built yourself.', fr: 'Vous voulez aller très haut et le faire selon votre propre chemin. La combinaison vous mène naturellement vers l\'entrepreneuriat. Tout type de succès ne convient pas — seulement celui que vous avez construit vous-même.', de: 'Du willst hoch hinaus und es auf deinem eigenen Weg tun. Diese Kombination führt dich natürlich zum Unternehmertum. Nicht jeder Erfolg taugt — nur der, den du selbst aufgebaut hast.', it: 'Vuoi arrivare in alto e farlo a modo tuo. Questa combinazione ti porta naturalmente all\'imprenditorialità. Non qualsiasi successo va bene — solo quello che hai costruito tu.', pt: 'Você quer chegar alto e fazer isso pelo seu próprio caminho. A combinação te leva naturalmente ao empreendedorismo. Não qualquer sucesso serve — apenas o que você mesmo/a construiu.' } },
        { name: { es: 'El Changemaker', en: 'The Changemaker', fr: 'Le Changemaker', de: 'Der Changemaker', it: 'Il Changemaker', pt: 'O Changemaker' }, dimensions: ['I', 'C'], photo: '/characters/changemaker.jpg', description: { es: 'Crecer para impactar más. Impactar para crecer más.', en: 'Grow to impact more. Impact to grow more.', fr: 'Grandir pour avoir plus d\'impact. Avoir de l\'impact pour grandir davantage.', de: 'Wachsen, um mehr Wirkung zu erzielen. Wirkung erzielen, um mehr zu wachsen.', it: 'Crescere per avere più impatto. Avere impatto per crescere di più.', pt: 'Crescer para impactar mais. Impactar para crescer mais.' }, philosophy: { es: 'Para ti, crecimiento e impacto se retroalimentan. Quieres ser mejor porque eso te permite hacer más bien. Y hacer el bien te impulsa a seguir creciendo. Es una espiral hacia arriba.', en: 'For you, growth and impact feed each other. You want to be better because it allows you to do more good. And doing good drives you to keep growing. It\'s an upward spiral.', fr: 'Pour vous, la croissance et l\'impact se nourrissent mutuellement. Vous voulez être meilleur parce que cela vous permet de faire plus de bien. Et faire le bien vous pousse à continuer à grandir. C\'est une spirale ascendante.', de: 'Für dich nähren sich Wachstum und Wirkung gegenseitig. Du willst besser werden, weil es dir ermöglicht, mehr Gutes zu tun. Und Gutes zu tun treibt dich an, weiter zu wachsen. Es ist eine aufwärts gerichtete Spirale.', it: 'Per te, crescita e impatto si alimentano a vicenda. Vuoi essere migliore perché ti permette di fare più bene. E fare del bene ti spinge a continuare a crescere. È una spirale verso l\'alto.', pt: 'Para você, crescimento e impacto se retroalimentam. Você quer ser melhor porque isso te permite fazer mais bem. E fazer o bem te impulsiona a continuar crescendo. É uma espiral ascendente.' } },
        { name: { es: 'El Fundador con Propósito', en: 'The Purpose-Driven Founder', fr: 'Le Fondateur avec un But', de: 'Der Zweckorientierte Gründer', it: 'Il Fondatore con Uno Scopo', pt: 'O Fundador com Propósito' }, dimensions: ['E', 'I'], photo: '/characters/purpose-founder.jpg', description: { es: 'Quiere éxito visible con impacto real.', en: 'Wants visible success with real impact.', fr: 'Veut un succès visible avec un impact réel.', de: 'Möchte sichtbaren Erfolg mit realer Wirkung.', it: 'Vuole successo visibile con impatto reale.', pt: 'Quer sucesso visível com impacto real.' }, philosophy: { es: 'No te conformas con uno de los dos. El éxito que no impacta no te satisface. El impacto que nadie ve tampoco. Quieres construir algo que sea grande y también significativo.', en: 'You\'re not satisfied with just one of the two. Success that has no impact doesn\'t satisfy you. Neither does impact that nobody sees. You want to build something that is both great and meaningful.', fr: 'Vous ne vous contentez pas de l\'un des deux. Le succès sans impact ne vous satisfait pas. L\'impact que personne ne voit non plus. Vous voulez construire quelque chose qui soit à la fois grand et significatif.', de: 'Du gibst dich nicht mit einem der beiden zufrieden. Erfolg ohne Wirkung befriedigt dich nicht. Impact, den niemand sieht, auch nicht. Du willst etwas aufbauen, das sowohl groß als auch bedeutsam ist.', it: 'Non ti accontenti di uno dei due. Il successo che non crea impatto non ti soddisfa. L\'impatto che nessuno vede neppure. Vuoi costruire qualcosa che sia grande e anche significativo.', pt: 'Você não se contenta com apenas um dos dois. O sucesso que não causa impacto não te satisfaz. O impacto que ninguém vê também não. Você quer construir algo que seja grande e também significativo.' } },
        { name: { es: 'El Sabio Profesional', en: 'The Wise Professional', fr: 'Le Sage Professionnel', de: 'Der Weise Profi', it: 'Il Saggio Professionista', pt: 'O Sábio Profissional' }, dimensions: ['A', 'C'], photo: '/characters/wise-professional.jpg', description: { es: 'Autónomo y en constante crecimiento. La combinación más difícil.', en: 'Autonomous and constantly growing. The most difficult combination.', fr: 'Autonome et en croissance constante. La combinaison la plus difficile.', de: 'Autonom und in ständigem Wachstum. Die schwierigste Kombination.', it: 'Autonomo e in costante crescita. La combinazione più difficile.', pt: 'Autônomo e em constante crescimento. A combinação mais difícil.' }, philosophy: { es: 'Quieres libertad para aprender a tu ritmo y en tu dirección. No necesitas que el mundo lo reconozca. Solo necesitas seguir siendo dueño/a de tu camino y seguir creciendo.', en: 'You want the freedom to learn at your own pace and in your own direction. You don\'t need the world to recognize it. You only need to remain the owner of your path and to keep growing.', fr: 'Vous voulez la liberté d\'apprendre à votre rythme et dans votre direction. Vous n\'avez pas besoin que le monde le reconnaisse. Vous avez juste besoin de rester maître/maîtresse de votre chemin et de continuer à grandir.', de: 'Du willst die Freiheit, in deinem eigenen Tempo und in deiner eigenen Richtung zu lernen. Du brauchst nicht, dass die Welt es anerkennt. Du musst nur Herr/Herrin deines Weges bleiben und weiter wachsen.', it: 'Vuoi la libertà di imparare al tuo ritmo e nella tua direzione. Non hai bisogno che il mondo lo riconosca. Hai solo bisogno di rimanere padrone/a del tuo percorso e di continuare a crescere.', pt: 'Você quer a liberdade de aprender no seu ritmo e na sua direção. Não precisa que o mundo reconheça isso. Só precisa continuar sendo dono/a do seu caminho e continuar crescendo.' } },
      ],
    },
    create: {
      slug: 'ambitious',
      title: { es: '¿Qué tipo de ambicioso/a eres?', en: 'What kind of ambitious person are you?', fr: 'Quel type d\'ambitieux/se êtes-vous?', de: 'Welcher Typ Ehrgeiziger bist du?', it: 'Che tipo di ambizioso/a sei?', pt: 'Que tipo de ambicioso/a você é?' },
      description: { es: 'La ambición mueve el mundo, pero no toda ambición es igual. ¿Qué mueve la tuya?', en: 'Ambition moves the world, but not all ambition is the same. What drives yours?', fr: 'L\'ambition fait bouger le monde, mais toutes les ambitions ne se valent pas. Qu\'est-ce qui anime la vôtre?', de: 'Ehrgeiz bewegt die Welt, aber nicht jeder Ehrgeiz ist gleich. Was treibt deinen an?', it: 'L\'ambizione muove il mondo, ma non tutta l\'ambizione è uguale. Cosa guida la tua?', pt: 'A ambição move o mundo, mas nem toda ambição é igual. O que move a sua?' },
      scenarioLabel: { es: 'Escenario', en: 'Scenario', fr: 'Scénario', de: 'Szenario', it: 'Scenario', pt: 'Cenário' },
      categoryId: catMap['life'],
      sortOrder: 1,
      dimensionLabels: {
        es: { E: 'Éxito Externo', I: 'Impacto', A: 'Autonomía', C: 'Crecimiento' },
        en: { E: 'External Success', I: 'Impact', A: 'Autonomy', C: 'Growth' },
        fr: { E: 'Succès Externe', I: 'Impact', A: 'Autonomie', C: 'Croissance' },
        de: { E: 'Äußerer Erfolg', I: 'Wirkung', A: 'Autonomie', C: 'Wachstum' },
        it: { E: 'Successo Esterno', I: 'Impatto', A: 'Autonomia', C: 'Crescita' },
        pt: { E: 'Sucesso Externo', I: 'Impacto', A: 'Autonomia', C: 'Crescimento' },
      },
      questions: [
        { id: 1, situation: { es: 'Te ofrecen un trabajo muy bien pagado que no te apasiona pero te dará seguridad y estatus. ¿Qué priorizas?', en: 'You are offered a very well-paid job that doesn\'t excite you but will give you security and status. What do you prioritize?', fr: 'On vous propose un travail très bien rémunéré qui ne vous passionne pas mais qui vous apportera sécurité et statut. Que priorisez-vous?', de: 'Dir wird eine sehr gut bezahlte Stelle angeboten, die dich nicht begeistert, aber dir Sicherheit und Status verschafft. Was priorisierst du?', it: 'Ti viene offerto un lavoro molto ben pagato che non ti appassiona ma ti darà sicurezza e status. Cosa priorizzi?', pt: 'Você recebe uma oferta de emprego muito bem pago que não te apaixona, mas que vai te dar segurança e status. O que você prioriza?' }, options: [{ text: { es: 'El dinero y el estatus. La pasión se cultiva, la estabilidad se construye.', en: 'Money and status. Passion can be cultivated, stability is built.', fr: 'L\'argent et le statut. La passion se cultive, la stabilité se construit.', de: 'Geld und Status. Leidenschaft kann kultiviert werden, Stabilität wird aufgebaut.', it: 'I soldi e lo status. La passione si coltiva, la stabilità si costruisce.', pt: 'O dinheiro e o status. A paixão se cultiva, a estabilidade se constrói.' }, dimension: 'E' }, { text: { es: 'Solo si genera algo real: cambia algo, ayuda a alguien.', en: 'Only if it creates something real: changes something, helps someone.', fr: 'Seulement si cela génère quelque chose de réel: change quelque chose, aide quelqu\'un.', de: 'Nur wenn es etwas Reales erzeugt: etwas verändert, jemandem hilft.', it: 'Solo se genera qualcosa di reale: cambia qualcosa, aiuta qualcuno.', pt: 'Somente se gerar algo real: mudar algo, ajudar alguém.' }, dimension: 'I' }, { text: { es: 'La flexibilidad y el control sobre mi tiempo. El dinero importa menos que la autonomía.', en: 'Flexibility and control over my time. Money matters less than autonomy.', fr: 'La flexibilité et le contrôle sur mon temps. L\'argent importe moins que l\'autonomie.', de: 'Flexibilität und Kontrolle über meine Zeit. Geld ist weniger wichtig als Autonomie.', it: 'La flessibilità e il controllo sul mio tempo. I soldi contano meno dell\'autonomia.', pt: 'A flexibilidade e o controle sobre meu tempo. O dinheiro importa menos que a autonomia.' }, dimension: 'A' }, { text: { es: 'Aprendo algo nuevo? ¿Me hace mejor? Eso es lo que evalúo.', en: 'Will I learn something new? Will it make me better? That\'s what I evaluate.', fr: 'Vais-je apprendre quelque chose de nouveau? Cela me rendra-t-il meilleur? C\'est ce que j\'évalue.', de: 'Lerne ich etwas Neues? Macht es mich besser? Das ist, was ich bewerte.', it: 'Imparerò qualcosa di nuovo? Mi renderà migliore? Questo è quello che valuto.', pt: 'Vou aprender algo novo? Vai me tornar melhor? Isso é o que avalio.' }, dimension: 'C' }] },
        { id: 2, situation: { es: '¿Qué significaría para ti haber "triunfado" en la vida?', en: 'What would it mean to you to have "succeeded" in life?', fr: 'Qu\'est-ce que cela signifierait pour vous d\'avoir "réussi" dans la vie?', de: 'Was würde es für dich bedeuten, im Leben "erfolgreich" gewesen zu sein?', it: 'Cosa significherebbe per te aver "trionfato" nella vita?', pt: 'O que significaria para você ter "triunfado" na vida?' }, options: [{ text: { es: 'Tener un nombre reconocido, recursos abundantes y respeto en mi campo.', en: 'Having a recognized name, abundant resources, and respect in my field.', fr: 'Avoir un nom reconnu, des ressources abondantes et du respect dans mon domaine.', de: 'Einen anerkannten Namen, reichliche Ressourcen und Respekt in meinem Bereich zu haben.', it: 'Avere un nome riconosciuto, risorse abbondanti e rispetto nel mio campo.', pt: 'Ter um nome reconhecido, recursos abundantes e respeito na minha área.' }, dimension: 'E' }, { text: { es: 'Haber cambiado la vida de personas de forma real y medible.', en: 'Having changed people\'s lives in a real and measurable way.', fr: 'Avoir changé la vie des gens de manière réelle et mesurable.', de: 'Das Leben von Menschen auf eine reale und messbare Weise verändert zu haben.', it: 'Aver cambiato la vita delle persone in modo reale e misurabile.', pt: 'Ter mudado a vida de pessoas de forma real e mensurável.' }, dimension: 'I' }, { text: { es: 'Vivir exactamente como quiero, sin que nadie me diga qué hacer.', en: 'Living exactly as I want, without anyone telling me what to do.', fr: 'Vivre exactement comme je veux, sans que personne ne me dise quoi faire.', de: 'Genau so zu leben, wie ich will, ohne dass mir jemand sagt, was ich tun soll.', it: 'Vivere esattamente come voglio, senza che nessuno mi dica cosa fare.', pt: 'Viver exatamente como quero, sem que ninguém me diga o que fazer.' }, dimension: 'A' }, { text: { es: 'Haber llegado a mi mejor versión, aunque nadie lo sepa.', en: 'Having reached my best self, even if nobody knows it.', fr: 'Avoir atteint ma meilleure version, même si personne ne le sait.', de: 'Meine beste Version erreicht zu haben, auch wenn es niemand weiß.', it: 'Essere arrivato/a alla mia migliore versione, anche se nessuno lo sa.', pt: 'Ter chegado à minha melhor versão, mesmo que ninguém saiba.' }, dimension: 'C' }] },
        { id: 3, situation: { es: 'Puedes elegir entre dos proyectos: uno te hará famoso/a, el otro cambiará silenciosamente la vida de miles.', en: 'You can choose between two projects: one will make you famous, the other will quietly change the lives of thousands.', fr: 'Vous pouvez choisir entre deux projets: l\'un vous rendra célèbre, l\'autre changera silencieusement la vie de milliers de personnes.', de: 'Du kannst zwischen zwei Projekten wählen: Eines wird dich berühmt machen, das andere wird still das Leben von Tausenden verändern.', it: 'Puoi scegliere tra due progetti: uno ti renderà famoso/a, l\'altro cambierà silenziosamente la vita di migliaia.', pt: 'Você pode escolher entre dois projetos: um vai te tornar famoso/a, o outro vai mudar silenciosamente a vida de milhares.' }, options: [{ text: { es: 'El que me da visibilidad. El impacto que no se ve no me mueve igual.', en: 'The one that gives me visibility. Impact that can\'t be seen doesn\'t move me the same way.', fr: 'Celui qui me donne de la visibilité. L\'impact qu\'on ne voit pas ne m\'anime pas autant.', de: 'Das, das mir Sichtbarkeit gibt. Wirkung, die man nicht sieht, bewegt mich nicht genauso.', it: 'Quello che mi dà visibilità. L\'impatto che non si vede non mi motiva allo stesso modo.', pt: 'O que me dá visibilidade. O impacto que não se vê não me move da mesma forma.' }, dimension: 'E' }, { text: { es: 'El que cambia vidas. La fama sin impacto real es ruido.', en: 'The one that changes lives. Fame without real impact is just noise.', fr: 'Celui qui change des vies. La célébrité sans impact réel n\'est que du bruit.', de: 'Das, das Leben verändert. Ruhm ohne reale Wirkung ist Lärm.', it: 'Quello che cambia vite. La fama senza impatto reale è solo rumore.', pt: 'O que muda vidas. A fama sem impacto real é apenas ruído.' }, dimension: 'I' }, { text: { es: 'El que me da más control sobre cómo trabajo y vivo.', en: 'The one that gives me more control over how I work and live.', fr: 'Celui qui me donne plus de contrôle sur la façon dont je travaille et vis.', de: 'Das, das mir mehr Kontrolle darüber gibt, wie ich arbeite und lebe.', it: 'Quello che mi dà più controllo su come lavoro e vivo.', pt: 'O que me dá mais controle sobre como trabalho e vivo.' }, dimension: 'A' }, { text: { es: 'El que me enseña más y me hace crecer más como profesional.', en: 'The one that teaches me more and helps me grow the most as a professional.', fr: 'Celui qui m\'apprend le plus et me fait le plus grandir en tant que professionnel.', de: 'Das, das mich mehr lehrt und mich als Profi am meisten wachsen lässt.', it: 'Quello che mi insegna di più e mi fa crescere di più come professionista.', pt: 'O que me ensina mais e me faz crescer mais como profissional.' }, dimension: 'C' }] },
        { id: 4, situation: { es: '¿Cuál es tu relación con el fracaso?', en: 'What is your relationship with failure?', fr: 'Quelle est votre relation avec l\'échec?', de: 'Was ist deine Beziehung zum Scheitern?', it: 'Qual è il tuo rapporto con il fallimento?', pt: 'Qual é a sua relação com o fracasso?' }, options: [{ text: { es: 'Es difícil. Fracasar en público me cuesta especialmente.', en: 'It\'s hard. Failing publicly is especially difficult for me.', fr: 'C\'est difficile. Échouer en public m\'est particulièrement difficile.', de: 'Es ist schwer. In der Öffentlichkeit zu scheitern fällt mir besonders schwer.', it: 'È difficile. Fallire in pubblico mi costa particolarmente.', pt: 'É difícil. Fracassar em público é especialmente custoso para mim.' }, dimension: 'E' }, { text: { es: 'Lo acepto si viene de intentar hacer algo que importa.', en: 'I accept it if it comes from trying to do something that matters.', fr: 'Je l\'accepte si cela vient d\'une tentative de faire quelque chose qui compte.', de: 'Ich akzeptiere es, wenn es davon kommt, etwas zu versuchen, das wichtig ist.', it: 'Lo accetto se viene dal tentativo di fare qualcosa che conta.', pt: 'Aceito se vem de tentar fazer algo que importa.' }, dimension: 'I' }, { text: { es: 'Lo vivo mejor si lo elegí yo, no si me fue impuesto.', en: 'I handle it better if I chose it, not if it was imposed on me.', fr: 'Je le vis mieux si je l\'ai choisi, pas s\'il m\'a été imposé.', de: 'Ich gehe damit besser um, wenn ich es gewählt habe, nicht wenn es mir aufgezwungen wurde.', it: 'Lo vivo meglio se l\'ho scelto io, non se mi è stato imposto.', pt: 'Lido melhor com ele se foi uma escolha minha, não se foi imposto.' }, dimension: 'A' }, { text: { es: 'Es información valiosa. Me dice qué necesito aprender.', en: 'It\'s valuable information. It tells me what I need to learn.', fr: 'C\'est une information précieuse. Cela me dit ce que je dois apprendre.', de: 'Es ist wertvolle Information. Es sagt mir, was ich lernen muss.', it: 'È un\'informazione preziosa. Mi dice cosa ho bisogno di imparare.', pt: 'É informação valiosa. Me diz o que preciso aprender.' }, dimension: 'C' }] },
        { id: 5, situation: { es: 'Un mentor influyente te ofrece guiarte, pero a cambio tendrás que seguir su visión, no la tuya.', en: 'An influential mentor offers to guide you, but in exchange you will have to follow their vision, not yours.', fr: 'Un mentor influent vous propose de vous guider, mais en échange vous devrez suivre sa vision, pas la vôtre.', de: 'Ein einflussreicher Mentor bietet an, dich zu führen, aber dafür musst du seine Vision verfolgen, nicht deine.', it: 'Un mentore influente ti offre di guidarti, ma in cambio dovrai seguire la sua visione, non la tua.', pt: 'Um mentor influente oferece orientá-lo, mas em troca você terá que seguir a visão dele, não a sua.' }, options: [{ text: { es: 'Lo acepto. El acceso a su red y su nombre vale el compromiso.', en: 'I accept it. Access to their network and name is worth the compromise.', fr: 'Je l\'accepte. L\'accès à son réseau et à son nom vaut le compromis.', de: 'Ich akzeptiere es. Der Zugang zu seinem Netzwerk und seinem Namen ist den Kompromiss wert.', it: 'Lo accetto. L\'accesso alla sua rete e al suo nome vale il compromesso.', pt: 'Aceito. O acesso à sua rede e seu nome vale o compromisso.' }, dimension: 'E' }, { text: { es: 'Depende de si su visión genera el mismo impacto que la mía.', en: 'It depends on whether their vision generates the same impact as mine.', fr: 'Cela dépend de si sa vision génère le même impact que la mienne.', de: 'Es hängt davon ab, ob seine Vision denselben Impact erzeugt wie meine.', it: 'Dipende se la sua visione genera lo stesso impatto della mia.', pt: 'Depende se a visão dele gera o mesmo impacto que a minha.' }, dimension: 'I' }, { text: { es: 'Lo rechazo. Prefiero construir más despacio con mi propia visión.', en: 'I turn it down. I prefer to build more slowly with my own vision.', fr: 'Je refuse. Je préfère construire plus lentement avec ma propre vision.', de: 'Ich lehne es ab. Ich baue lieber langsamer mit meiner eigenen Vision.', it: 'Lo rifiuto. Preferisco costruire più lentamente con la mia visione.', pt: 'Recuso. Prefiro construir mais devagar com minha própria visão.' }, dimension: 'A' }, { text: { es: 'Depende de cuánto puedo aprender de él/ella en el proceso.', en: 'It depends on how much I can learn from them in the process.', fr: 'Cela dépend de combien je peux apprendre d\'eux dans le processus.', de: 'Es hängt davon ab, wie viel ich von ihm/ihr im Prozess lernen kann.', it: 'Dipende da quanto posso imparare da lui/lei nel processo.', pt: 'Depende de quanto posso aprender com ele/ela no processo.' }, dimension: 'C' }] },
        { id: 6, situation: { es: '¿Qué te motiva más a trabajar duro?', en: 'What motivates you most to work hard?', fr: 'Qu\'est-ce qui vous motive le plus à travailler dur?', de: 'Was motiviert dich am meisten, hart zu arbeiten?', it: 'Cosa ti motiva di più a lavorare sodo?', pt: 'O que te motiva mais a trabalhar duro?' }, options: [{ text: { es: 'El reconocimiento de pares y la posición que construyo.', en: 'Peer recognition and the position I\'m building.', fr: 'La reconnaissance de mes pairs et la position que je construis.', de: 'Die Anerkennung von Gleichgestellten und die Position, die ich aufbaue.', it: 'Il riconoscimento dei colleghi e la posizione che sto costruendo.', pt: 'O reconhecimento dos pares e a posição que estou construindo.' }, dimension: 'E' }, { text: { es: 'Saber que lo que hago importa y tiene un efecto real.', en: 'Knowing that what I do matters and has a real effect.', fr: 'Savoir que ce que je fais compte et a un effet réel.', de: 'Zu wissen, dass das, was ich tue, wichtig ist und eine reale Wirkung hat.', it: 'Sapere che quello che faccio conta e ha un effetto reale.', pt: 'Saber que o que faço importa e tem um efeito real.' }, dimension: 'I' }, { text: { es: 'La libertad que me da no depender de nadie.', en: 'The freedom that comes from not depending on anyone.', fr: 'La liberté que cela me donne de ne dépendre de personne.', de: 'Die Freiheit, die es mir gibt, von niemandem abhängig zu sein.', it: 'La libertà che mi dà non dipendere da nessuno.', pt: 'A liberdade que me dá não depender de ninguém.' }, dimension: 'A' }, { text: { es: 'La sensación de mejorar, de ser hoy mejor que ayer.', en: 'The feeling of improving, of being better today than yesterday.', fr: 'La sensation de progresser, d\'être meilleur aujourd\'hui qu\'hier.', de: 'Das Gefühl, sich zu verbessern, heute besser zu sein als gestern.', it: 'La sensazione di migliorare, di essere oggi migliore di ieri.', pt: 'A sensação de melhorar, de ser hoje melhor do que ontem.' }, dimension: 'C' }] },
        { id: 7, situation: { es: 'Tienes que elegir entre un ascenso con más poder o un rol horizontal con más aprendizaje.', en: 'You have to choose between a promotion with more power or a lateral role with more learning.', fr: 'Vous devez choisir entre une promotion avec plus de pouvoir ou un rôle horizontal avec plus d\'apprentissage.', de: 'Du musst zwischen einer Beförderung mit mehr Macht oder einer lateralen Rolle mit mehr Lernen wählen.', it: 'Devi scegliere tra una promozione con più potere o un ruolo orizzontale con più apprendimento.', pt: 'Você tem que escolher entre uma promoção com mais poder ou um cargo lateral com mais aprendizado.' }, options: [{ text: { es: 'El ascenso. El poder amplifica todo lo demás.', en: 'The promotion. Power amplifies everything else.', fr: 'La promotion. Le pouvoir amplifie tout le reste.', de: 'Die Beförderung. Macht verstärkt alles andere.', it: 'La promozione. Il potere amplifica tutto il resto.', pt: 'A promoção. O poder amplifica tudo o mais.' }, dimension: 'E' }, { text: { es: 'El que me permita tener más impacto, sea cual sea.', en: 'Whichever allows me to have more impact, regardless.', fr: 'Celui qui me permet d\'avoir plus d\'impact, quel qu\'il soit.', de: 'Das, das mir mehr Impact ermöglicht, egal welches.', it: 'Quello che mi permette di avere più impatto, qualunque esso sia.', pt: 'O que me permita ter mais impacto, seja qual for.' }, dimension: 'I' }, { text: { es: 'El horizontal. Más aprendizaje, más opciones futuras, más libertad.', en: 'The lateral one. More learning, more future options, more freedom.', fr: 'Le rôle horizontal. Plus d\'apprentissage, plus d\'options futures, plus de liberté.', de: 'Der laterale. Mehr Lernen, mehr zukünftige Optionen, mehr Freiheit.', it: 'Quello orizzontale. Più apprendimento, più opzioni future, più libertà.', pt: 'O lateral. Mais aprendizado, mais opções futuras, mais liberdade.' }, dimension: 'A' }, { text: { es: 'El de más aprendizaje. Siempre.', en: 'The one with more learning. Always.', fr: 'Celui avec plus d\'apprentissage. Toujours.', de: 'Das mit mehr Lernen. Immer.', it: 'Quello con più apprendimento. Sempre.', pt: 'O de mais aprendizado. Sempre.' }, dimension: 'C' }] },
        { id: 8, situation: { es: '¿Qué es lo que más te frustra de las personas que trabajan sin ambición?', en: 'What frustrates you most about people who work without ambition?', fr: 'Qu\'est-ce qui vous frustre le plus chez les gens qui travaillent sans ambition?', de: 'Was frustriert dich am meisten an Menschen, die ohne Ehrgeiz arbeiten?', it: 'Cosa ti frustra di più nelle persone che lavorano senza ambizione?', pt: 'O que mais te frustra nas pessoas que trabalham sem ambição?' }, options: [{ text: { es: 'Que desperdician su potencial de crear algo grande.', en: 'That they waste their potential to create something great.', fr: 'Qu\'ils gaspillent leur potentiel pour créer quelque chose de grand.', de: 'Dass sie ihr Potenzial verschwenden, etwas Großes zu schaffen.', it: 'Che sprecano il loro potenziale per creare qualcosa di grande.', pt: 'Que desperdiçam seu potencial de criar algo grande.' }, dimension: 'E' }, { text: { es: 'Que su falta de ambición los lleva a no mejorar el mundo cuando podrían.', en: 'That their lack of ambition leads them to not improve the world when they could.', fr: 'Que leur manque d\'ambition les amène à ne pas améliorer le monde alors qu\'ils le pourraient.', de: 'Dass ihr mangelnder Ehrgeiz dazu führt, dass sie die Welt nicht verbessern, obwohl sie es könnten.', it: 'Che la loro mancanza di ambizione li porta a non migliorare il mondo quando potrebbero.', pt: 'Que a falta de ambição os leva a não melhorar o mundo quando poderiam.' }, dimension: 'I' }, { text: { es: 'Que se dejan llevar por sistemas que no los representan sin cuestionarlos.', en: 'That they let themselves be swept along by systems that don\'t represent them without questioning them.', fr: 'Qu\'ils se laissent emporter par des systèmes qui ne les représentent pas sans les remettre en question.', de: 'Dass sie sich von Systemen mitreißen lassen, die sie nicht repräsentieren, ohne sie zu hinterfragen.', it: 'Che si lasciano trascinare da sistemi che non li rappresentano senza metterli in discussione.', pt: 'Que se deixam levar por sistemas que não os representam sem questioná-los.' }, dimension: 'A' }, { text: { es: 'Que se estancan y dejan de aprender.', en: 'That they stagnate and stop learning.', fr: 'Qu\'ils stagnent et arrêtent d\'apprendre.', de: 'Dass sie stagnieren und aufhören zu lernen.', it: 'Che si bloccano e smettono di imparare.', pt: 'Que estagnam e param de aprender.' }, dimension: 'C' }] },
        { id: 9, situation: { es: 'Tienes la oportunidad de dar un salto enorme en tu carrera, pero requiere sacrificar relaciones importantes.', en: 'You have the opportunity to make a huge leap in your career, but it requires sacrificing important relationships.', fr: 'Vous avez l\'opportunité de faire un grand bond dans votre carrière, mais cela nécessite de sacrifier des relations importantes.', de: 'Du hast die Möglichkeit, einen enormen Sprung in deiner Karriere zu machen, aber es erfordert, wichtige Beziehungen zu opfern.', it: 'Hai l\'opportunità di fare un grande salto nella tua carriera, ma richiede di sacrificare relazioni importanti.', pt: 'Você tem a oportunidade de dar um salto enorme na carreira, mas requer sacrificar relacionamentos importantes.' }, options: [{ text: { es: 'Lo evalúo seriamente. Hay etapas de la vida donde hay que priorizar.', en: 'I evaluate it seriously. There are stages in life where you have to prioritize.', fr: 'Je l\'évalue sérieusement. Il y a des étapes de la vie où il faut prioriser.', de: 'Ich bewerte es ernsthaft. Es gibt Phasen im Leben, in denen man priorisieren muss.', it: 'Lo valuto seriamente. Ci sono fasi della vita in cui bisogna dare priorità.', pt: 'Avalio seriamente. Há etapas da vida em que se precisa priorizar.' }, dimension: 'E' }, { text: { es: 'Solo si ese salto tiene un propósito que lo justifique más allá del éxito personal.', en: 'Only if that leap has a purpose that justifies it beyond personal success.', fr: 'Seulement si ce bond a un objectif qui le justifie au-delà du succès personnel.', de: 'Nur wenn dieser Sprung einen Zweck hat, der ihn jenseits persönlichen Erfolgs rechtfertigt.', it: 'Solo se quel salto ha uno scopo che lo giustifica al di là del successo personale.', pt: 'Somente se esse salto tiver um propósito que o justifique além do sucesso pessoal.' }, dimension: 'I' }, { text: { es: 'Busco la forma de hacer el salto sin sacrificar lo que más valoro.', en: 'I look for a way to make the leap without sacrificing what I value most.', fr: 'Je cherche une façon de faire le bond sans sacrifier ce que je valorise le plus.', de: 'Ich suche nach einer Möglichkeit, den Sprung zu machen, ohne das zu opfern, was mir am wichtigsten ist.', it: 'Cerco il modo di fare il salto senza sacrificare ciò che valuto di più.', pt: 'Procuro a forma de dar o salto sem sacrificar o que mais valorizo.' }, dimension: 'A' }, { text: { es: 'Si el crecimiento profesional destruye lo que construí, algo en la ecuación está mal.', en: 'If professional growth destroys what I\'ve built, something in the equation is wrong.', fr: 'Si la croissance professionnelle détruit ce que j\'ai construit, quelque chose dans l\'équation est faux.', de: 'Wenn berufliches Wachstum das zerstört, was ich aufgebaut habe, stimmt etwas in der Gleichung nicht.', it: 'Se la crescita professionale distrugge quello che ho costruito, qualcosa nell\'equazione è sbagliato.', pt: 'Se o crescimento profissional destrói o que construí, algo na equação está errado.' }, dimension: 'C' }] },
        { id: 10, situation: { es: 'Al final de tu carrera, ¿qué quieres que digan de ti?', en: 'At the end of your career, what do you want people to say about you?', fr: 'À la fin de votre carrière, que voulez-vous qu\'on dise de vous?', de: 'Am Ende deiner Karriere, was willst du, dass die Leute über dich sagen?', it: 'Alla fine della tua carriera, cosa vuoi che dicano di te?', pt: 'No final da sua carreira, o que você quer que digam sobre você?' }, options: [{ text: { es: '"Llegó muy lejos. Era brillante y todos lo sabían."', en: '"They went very far. They were brilliant, and everyone knew it."', fr: '"Il/elle est allé(e) très loin. Il/elle était brillant(e) et tout le monde le savait."', de: '"Er/Sie ist sehr weit gekommen. Er/Sie war brilliant und alle wussten es."', it: '"È arrivato/a molto lontano. Era brillante e tutti lo sapevano."', pt: '"Foi muito longe. Era brilhante e todos sabiam."' }, dimension: 'E' }, { text: { es: '"Cambió algo. Antes de él/ella, esto era diferente."', en: '"They changed something. Before them, this was different."', fr: '"Il/elle a changé quelque chose. Avant lui/elle, c\'était différent."', de: '"Er/Sie hat etwas verändert. Vor ihm/ihr war das anders."', it: '"Ha cambiato qualcosa. Prima di lui/lei, era diverso."', pt: '"Mudou algo. Antes dele/dela, isso era diferente."' }, dimension: 'I' }, { text: { es: '"Vivió en sus propios términos. Nunca transigió su independencia."', en: '"They lived on their own terms. They never compromised their independence."', fr: '"Il/elle a vécu selon ses propres termes. Il/elle n\'a jamais transigé sur son indépendance."', de: '"Er/Sie lebte nach seinen/ihren eigenen Bedingungen. Er/Sie hat seine/ihre Unabhängigkeit nie kompromittiert."', it: '"Ha vissuto alle sue condizioni. Non ha mai compromesso la sua indipendenza."', pt: '"Viveu nos seus próprios termos. Nunca comprometeu a sua independência."' }, dimension: 'A' }, { text: { es: '"Nunca dejó de aprender y crecer. Era mejor cada año."', en: '"They never stopped learning and growing. They were better every year."', fr: '"Il/elle n\'a jamais arrêté d\'apprendre et de grandir. Il/elle était meilleur(e) chaque année."', de: '"Er/Sie hörte nie auf zu lernen und zu wachsen. Er/Sie wurde jedes Jahr besser."', it: '"Non ha mai smesso di imparare e crescere. Era migliore ogni anno."', pt: '"Nunca parou de aprender e crescer. Era melhor a cada ano."' }, dimension: 'C' }] },
      ],
      characters: [
        { name: { es: 'El Ambicioso de Éxito', en: 'The Success-Driven Ambitious', fr: 'L\'Ambitieux de la Réussite', de: 'Der Erfolgsambitionierte', it: 'L\'Ambizioso del Successo', pt: 'O Ambicioso de Sucesso' }, dimensions: ['E'], photo: '/characters/success-ambitious.jpg', description: { es: 'Quiere llegar alto y que todos lo vean.', en: 'Wants to reach the top and have everyone see it.', fr: 'Veut aller très haut et que tout le monde le voit.', de: 'Möchte hoch hinaus und dass alle es sehen.', it: 'Vuole arrivare in alto e che tutti lo vedano.', pt: 'Quer chegar alto e que todos vejam.' }, philosophy: { es: 'Para ti, el éxito tiene nombre, número y audiencia. No es vanidad — es la evidencia concreta de que valió la pena el esfuerzo. El reconocimiento externo es el espejo donde mides tu propio valor.', en: 'For you, success has a name, a number, and an audience. It\'s not vanity — it\'s concrete evidence that the effort was worth it. External recognition is the mirror in which you measure your own worth.', fr: 'Pour vous, le succès a un nom, un chiffre et un public. Ce n\'est pas de la vanité — c\'est la preuve concrète que l\'effort en valait la peine. La reconnaissance externe est le miroir dans lequel vous mesurez votre propre valeur.', de: 'Für dich hat Erfolg einen Namen, eine Zahl und ein Publikum. Es ist keine Eitelkeit — es ist der konkrete Beweis, dass die Mühe es wert war. Externe Anerkennung ist der Spiegel, in dem du deinen eigenen Wert misst.', it: 'Per te, il successo ha un nome, un numero e un pubblico. Non è vanità — è la prova concreta che lo sforzo ne è valso la pena. Il riconoscimento esterno è lo specchio in cui misuri il tuo stesso valore.', pt: 'Para você, o sucesso tem nome, número e audiência. Não é vaidade — é a evidência concreta de que o esforço valeu a pena. O reconhecimento externo é o espelho onde você mede o seu próprio valor.' } },
        { name: { es: 'El Ambicioso de Impacto', en: 'The Impact-Driven Ambitious', fr: 'L\'Ambitieux de l\'Impact', de: 'Der Wirkungsorientierte', it: 'L\'Ambizioso dell\'Impatto', pt: 'O Ambicioso de Impacto' }, dimensions: ['I'], photo: '/characters/impact-ambitious.jpg', description: { es: 'Le importa dejar huella, no tener fama.', en: 'Cares about leaving a mark, not gaining fame.', fr: 'S\'intéresse à laisser une empreinte, pas à avoir de la célébrité.', de: 'Wichtig ist, eine Spur zu hinterlassen, nicht berühmt zu werden.', it: 'Gli/Le importa lasciare un\'impronta, non avere fama.', pt: 'Importa-se em deixar uma marca, não em ter fama.' }, philosophy: { es: 'Para ti, la ambición sin propósito es ruido. Quieres que lo que hagas importe, que cambie algo, que quede cuando ya no estés. El éxito sin impacto real es decoración.', en: 'For you, ambition without purpose is noise. You want what you do to matter, to change something, to remain when you\'re gone. Success without real impact is mere decoration.', fr: 'Pour vous, l\'ambition sans but n\'est que du bruit. Vous voulez que ce que vous faites compte, que cela change quelque chose, que cela reste quand vous ne serez plus là. Le succès sans impact réel n\'est que décoration.', de: 'Für dich ist Ehrgeiz ohne Zweck Lärm. Du willst, dass das, was du tust, wichtig ist, etwas verändert, bleibt, wenn du nicht mehr da bist. Erfolg ohne reale Wirkung ist nur Dekoration.', it: 'Per te, l\'ambizione senza scopo è rumore. Vuoi che quello che fai conti, che cambi qualcosa, che rimanga quando non ci sarai più. Il successo senza impatto reale è semplice decorazione.', pt: 'Para você, a ambição sem propósito é ruído. Você quer que o que faz importe, que mude algo, que permaneça quando você não estiver mais aqui. O sucesso sem impacto real é apenas decoração.' } },
        { name: { es: 'El Ambicioso Independiente', en: 'The Independent Ambitious', fr: 'L\'Ambitieux Indépendant', de: 'Der Unabhängige Ehrgeizige', it: 'L\'Ambizioso Indipendente', pt: 'O Ambicioso Independente' }, dimensions: ['A'], photo: '/characters/independent-ambitious.jpg', description: { es: 'Quiere construir, pero en sus propios términos.', en: 'Wants to build, but on their own terms.', fr: 'Veut construire, mais selon ses propres termes.', de: 'Möchte aufbauen, aber zu seinen eigenen Bedingungen.', it: 'Vuole costruire, ma a modo suo.', pt: 'Quer construir, mas nos seus próprios termos.' }, philosophy: { es: 'Tu ambición más profunda es la libertad. No cualquier tipo de éxito — solo el que te permite vivir según tus reglas. Preferirías un negocio pequeño propio que una posición poderosa en el sistema de otro.', en: 'Your deepest ambition is freedom. Not just any kind of success — only the kind that lets you live by your own rules. You would rather have a small business of your own than a powerful position in someone else\'s system.', fr: 'Votre ambition la plus profonde est la liberté. Pas n\'importe quel type de succès — seulement celui qui vous permet de vivre selon vos propres règles. Vous préféreriez une petite entreprise qui vous appartient qu\'une position puissante dans le système de quelqu\'un d\'autre.', de: 'Dein tiefster Ehrgeiz ist die Freiheit. Nicht irgendeine Art von Erfolg — nur der, der es dir ermöglicht, nach deinen eigenen Regeln zu leben. Du würdest lieber ein kleines eigenes Unternehmen haben als eine mächtige Position im System eines anderen.', it: 'La tua ambizione più profonda è la libertà. Non qualsiasi tipo di successo — solo quello che ti permette di vivere secondo le tue regole. Preferiresti una piccola impresa tua che una posizione potente nel sistema di qualcun altro.', pt: 'Sua ambição mais profunda é a liberdade. Não qualquer tipo de sucesso — apenas o que te permite viver segundo as suas regras. Preferiria um pequeno negócio próprio a uma posição poderosa no sistema de outra pessoa.' } },
        { name: { es: 'El Ambicioso de Crecimiento', en: 'The Growth-Driven Ambitious', fr: 'L\'Ambitieux de la Croissance', de: 'Der Wachstumsorientierte', it: 'L\'Ambizioso della Crescita', pt: 'O Ambicioso do Crescimento' }, dimensions: ['C'], photo: '/characters/growth-ambitious.jpg', description: { es: 'Cada día mejor que ayer. Eso es suficiente.', en: 'Better every day than the one before. That is enough.', fr: 'Chaque jour meilleur que la veille. C\'est suffisant.', de: 'Jeden Tag besser als gestern. Das genügt.', it: 'Ogni giorno migliore di ieri. Questo è sufficiente.', pt: 'Cada dia melhor do que o anterior. Isso é suficiente.' }, philosophy: { es: 'Para ti, la ambición es interna. El estándar con quien compites eres tú mismo/a de ayer. No te interesa ser el mejor del mundo — te interesa ser la mejor versión de ti mismo/a.', en: 'For you, ambition is internal. The standard you compete against is your yesterday self. You\'re not interested in being the best in the world — you\'re interested in being the best version of yourself.', fr: 'Pour vous, l\'ambition est interne. La norme avec laquelle vous vous comparez, c\'est vous-même d\'hier. Vous ne cherchez pas à être le meilleur du monde — vous cherchez à être la meilleure version de vous-même.', de: 'Für dich ist Ehrgeiz intern. Der Standard, mit dem du konkurrierst, bist du selbst von gestern. Du interessierst dich nicht dafür, der Beste der Welt zu sein — du interessierst dich dafür, die beste Version deiner selbst zu sein.', it: 'Per te, l\'ambizione è interna. Lo standard con cui gareggi sei tu stesso/a di ieri. Non ti interessa essere il migliore del mondo — ti interessa essere la migliore versione di te stesso/a.', pt: 'Para você, a ambição é interna. O padrão com quem você compete é você mesmo/a de ontem. Não lhe interessa ser o melhor do mundo — lhe interessa ser a melhor versão de si mesmo/a.' } },
        { name: { es: 'El Emprendedor Ambicioso', en: 'The Ambitious Entrepreneur', fr: 'L\'Entrepreneur Ambitieux', de: 'Der Ehrgeizige Unternehmer', it: 'L\'Imprenditore Ambizioso', pt: 'O Empreendedor Ambicioso' }, dimensions: ['E', 'A'], photo: '/characters/entrepreneur.jpg', description: { es: 'Quiere éxito y autonomía. El camino del fundador.', en: 'Wants success and autonomy. The founder\'s path.', fr: 'Veut réussite et autonomie. La voie du fondateur.', de: 'Möchte Erfolg und Autonomie. Der Weg des Gründers.', it: 'Vuole successo e autonomia. Il percorso del fondatore.', pt: 'Quer sucesso e autonomia. O caminho do fundador.' }, philosophy: { es: 'Quieres llegar alto y hacerlo por tu propio camino. La combinación te lleva naturalmente al emprendimiento. No cualquier éxito sirve — solo el que construiste tú.', en: 'You want to reach the top and do it your own way. This combination naturally leads you to entrepreneurship. Not just any success will do — only the one you built yourself.', fr: 'Vous voulez aller très haut et le faire selon votre propre chemin. La combinaison vous mène naturellement vers l\'entrepreneuriat. Tout type de succès ne convient pas — seulement celui que vous avez construit vous-même.', de: 'Du willst hoch hinaus und es auf deinem eigenen Weg tun. Diese Kombination führt dich natürlich zum Unternehmertum. Nicht jeder Erfolg taugt — nur der, den du selbst aufgebaut hast.', it: 'Vuoi arrivare in alto e farlo a modo tuo. Questa combinazione ti porta naturalmente all\'imprenditorialità. Non qualsiasi successo va bene — solo quello che hai costruito tu.', pt: 'Você quer chegar alto e fazer isso pelo seu próprio caminho. A combinação te leva naturalmente ao empreendedorismo. Não qualquer sucesso serve — apenas o que você mesmo/a construiu.' } },
        { name: { es: 'El Changemaker', en: 'The Changemaker', fr: 'Le Changemaker', de: 'Der Changemaker', it: 'Il Changemaker', pt: 'O Changemaker' }, dimensions: ['I', 'C'], photo: '/characters/changemaker.jpg', description: { es: 'Crecer para impactar más. Impactar para crecer más.', en: 'Grow to impact more. Impact to grow more.', fr: 'Grandir pour avoir plus d\'impact. Avoir de l\'impact pour grandir davantage.', de: 'Wachsen, um mehr Wirkung zu erzielen. Wirkung erzielen, um mehr zu wachsen.', it: 'Crescere per avere più impatto. Avere impatto per crescere di più.', pt: 'Crescer para impactar mais. Impactar para crescer mais.' }, philosophy: { es: 'Para ti, crecimiento e impacto se retroalimentan. Quieres ser mejor porque eso te permite hacer más bien. Y hacer el bien te impulsa a seguir creciendo. Es una espiral hacia arriba.', en: 'For you, growth and impact feed each other. You want to be better because it allows you to do more good. And doing good drives you to keep growing. It\'s an upward spiral.', fr: 'Pour vous, la croissance et l\'impact se nourrissent mutuellement. Vous voulez être meilleur parce que cela vous permet de faire plus de bien. Et faire le bien vous pousse à continuer à grandir. C\'est une spirale ascendante.', de: 'Für dich nähren sich Wachstum und Wirkung gegenseitig. Du willst besser werden, weil es dir ermöglicht, mehr Gutes zu tun. Und Gutes zu tun treibt dich an, weiter zu wachsen. Es ist eine aufwärts gerichtete Spirale.', it: 'Per te, crescita e impatto si alimentano a vicenda. Vuoi essere migliore perché ti permette di fare più bene. E fare del bene ti spinge a continuare a crescere. È una spirale verso l\'alto.', pt: 'Para você, crescimento e impacto se retroalimentam. Você quer ser melhor porque isso te permite fazer mais bem. E fazer o bem te impulsiona a continuar crescendo. É uma espiral ascendente.' } },
        { name: { es: 'El Fundador con Propósito', en: 'The Purpose-Driven Founder', fr: 'Le Fondateur avec un But', de: 'Der Zweckorientierte Gründer', it: 'Il Fondatore con Uno Scopo', pt: 'O Fundador com Propósito' }, dimensions: ['E', 'I'], photo: '/characters/purpose-founder.jpg', description: { es: 'Quiere éxito visible con impacto real.', en: 'Wants visible success with real impact.', fr: 'Veut un succès visible avec un impact réel.', de: 'Möchte sichtbaren Erfolg mit realer Wirkung.', it: 'Vuole successo visibile con impatto reale.', pt: 'Quer sucesso visível com impacto real.' }, philosophy: { es: 'No te conformas con uno de los dos. El éxito que no impacta no te satisface. El impacto que nadie ve tampoco. Quieres construir algo que sea grande y también significativo.', en: 'You\'re not satisfied with just one of the two. Success that has no impact doesn\'t satisfy you. Neither does impact that nobody sees. You want to build something that is both great and meaningful.', fr: 'Vous ne vous contentez pas de l\'un des deux. Le succès sans impact ne vous satisfait pas. L\'impact que personne ne voit non plus. Vous voulez construire quelque chose qui soit à la fois grand et significatif.', de: 'Du gibst dich nicht mit einem der beiden zufrieden. Erfolg ohne Wirkung befriedigt dich nicht. Impact, den niemand sieht, auch nicht. Du willst etwas aufbauen, das sowohl groß als auch bedeutsam ist.', it: 'Non ti accontenti di uno dei due. Il successo che non crea impatto non ti soddisfa. L\'impatto che nessuno vede neppure. Vuoi costruire qualcosa che sia grande e anche significativo.', pt: 'Você não se contenta com apenas um dos dois. O sucesso que não causa impacto não te satisfaz. O impacto que ninguém vê também não. Você quer construir algo que seja grande e também significativo.' } },
        { name: { es: 'El Sabio Profesional', en: 'The Wise Professional', fr: 'Le Sage Professionnel', de: 'Der Weise Profi', it: 'Il Saggio Professionista', pt: 'O Sábio Profissional' }, dimensions: ['A', 'C'], photo: '/characters/wise-professional.jpg', description: { es: 'Autónomo y en constante crecimiento. La combinación más difícil.', en: 'Autonomous and constantly growing. The most difficult combination.', fr: 'Autonome et en croissance constante. La combinaison la plus difficile.', de: 'Autonom und in ständigem Wachstum. Die schwierigste Kombination.', it: 'Autonomo e in costante crescita. La combinazione più difficile.', pt: 'Autônomo e em constante crescimento. A combinação mais difícil.' }, philosophy: { es: 'Quieres libertad para aprender a tu ritmo y en tu dirección. No necesitas que el mundo lo reconozca. Solo necesitas seguir siendo dueño/a de tu camino y seguir creciendo.', en: 'You want the freedom to learn at your own pace and in your own direction. You don\'t need the world to recognize it. You only need to remain the owner of your path and to keep growing.', fr: 'Vous voulez la liberté d\'apprendre à votre rythme et dans votre direction. Vous n\'avez pas besoin que le monde le reconnaisse. Vous avez juste besoin de rester maître/maîtresse de votre chemin et de continuer à grandir.', de: 'Du willst die Freiheit, in deinem eigenen Tempo und in deiner eigenen Richtung zu lernen. Du brauchst nicht, dass die Welt es anerkennt. Du musst nur Herr/Herrin deines Weges bleiben und weiter wachsen.', it: 'Vuoi la libertà di imparare al tuo ritmo e nella tua direzione. Non hai bisogno che il mondo lo riconosca. Hai solo bisogno di rimanere padrone/a del tuo percorso e di continuare a crescere.', pt: 'Você quer a liberdade de aprender no seu ritmo e na sua direção. Não precisa que o mundo reconheça isso. Só precisa continuar sendo dono/a do seu caminho e continuar crescendo.' } },
      ],
    },
  });
}
